commit 3aee0f27d44247844c464e7a77c526f59cf62b3e
Author: Shiju Jose <shiju.jose@huawei.com>

ras: mem: Add ACPI RAS2 memory driver

Driver adds support for the ACPI RAS2 feature table, providing interfaces
for platform RAS features like HW-based memory scrubbing. It registers
an auxiliary driver and exposes scrub control attributes to userspace via
the EDAC scrub interface.

> diff --git a/drivers/ras/acpi_ras2.c b/drivers/ras/acpi_ras2.c
> --- /dev/null
> +++ b/drivers/ras/acpi_ras2.c

[ ... ]

> +static int ras2_update_patrol_scrub_params_cache(struct ras2_mem_ctx *ras2_ctx)
> +{
> +	struct acpi_ras2_ps_shared_mem __iomem *ps_sm =
> +		TO_ACPI_RAS2_PS_SHMEM(ras2_ctx->comm_addr);
> +	int ret;
> +
> +	ps_sm->common.set_caps[0] = RAS2_SUPPORT_HW_PARTOL_SCRUB;
> +	ps_sm->params.command = RAS2_GET_PATROL_PARAMETERS;
> +	ps_sm->params.req_addr_range[0] = ras2_ctx->mem_base;
> +	ps_sm->params.req_addr_range[1] = ras2_ctx->mem_size;

Are these direct assignments to the __iomem pointer safe here?

Since PCC structures are defined by ACPI as little-endian, will writing
native CPU-endian variables like the u64 mem_base cause the firmware to
receive corrupted configurations on big-endian architectures?

Should I/O accessors like iowrite32() or memcpy_toio() be used instead?

[ ... ]

> +static int ras2_scrub_monitor_thread(void *p)
> +{
> +	struct ras2_mem_ctx *ras2_ctx = (struct ras2_mem_ctx *)p;
> +	bool running;
> +	int ret;
> +
> +	while (!kthread_should_stop()) {
> +		if (!ras2_ctx->reenable_bg_scrub)
> +			return 0;
> +
> +		mutex_lock(ras2_ctx->pcc_lock);
> +		ret = ras2_get_demand_scrub_running(ras2_ctx, &running);
> +		mutex_unlock(ras2_ctx->pcc_lock);
> +		if (ret)
> +			return ret;
> +
> +		if (!running) {
> +			ras2_ctx->base = 0;
> +			ras2_ctx->size = 0;

Does clearing the base and size outside of the pcc_lock create a data race
against ras2_hw_scrub_write_addr() and ras2_hw_scrub_write_size()?

If a user stages a new address configuration immediately after a scrub
finishes, could their values be asynchronously clobbered by this thread?

> +			return ras2_hw_scrub_set_enabled_bg(ras2_ctx->dev, ras2_ctx, true);
> +		}
> +		msleep(1000);
> +	}
> +
> +	return 0;
> +}

[ ... ]

> +static int ras2_hw_scrub_read_addr(struct device *dev, void *drv_data, u64 *base)
> +{
> +	struct ras2_mem_ctx *ras2_ctx = drv_data;
> +	int ret;
> +
> +	/*
> +	 * When BG scrubbing is enabled the actual address range is not valid.
> +	 * Return -EBUSY now unless find out a method to retrieve actual full PA range.
> +	 */
> +	if (ras2_ctx->bg_scrub)
> +		return -EBUSY;
> +
> +	ret = ras2_update_patrol_scrub_params_cache(ras2_ctx);

Since ras2_update_patrol_scrub_params_cache() writes commands to the
hardware shared memory, can calling it here without holding the pcc_lock
cause data races? Concurrent sysfs reads or writes could interleave
modifications to the shared communication buffer.

Also, ras2_update_patrol_scrub_params_cache() unconditionally fetches the
active parameters and updates ras2_ctx->scrub_cycle_hrs. If a user stages a
new scrub_cycle_hrs and then reads the addr or size sysfs attributes before
starting the scrub, will their staged configuration be silently overwritten
and destroyed?

> +	if (ret)
> +		return ret;
> +
> +	*base = ras2_ctx->base;
> +
> +	return 0;
> +}

[ ... ]

> +static int ras2_hw_scrub_set_enabled_od(struct device *dev, void *drv_data, bool enable)
> +{
> +	struct ras2_mem_ctx *ras2_ctx = drv_data;
> +	struct acpi_ras2_ps_shared_mem __iomem *ps_sm = TO_ACPI_RAS2_PS_SHMEM(ras2_ctx->comm_addr);
> +	struct task_struct *thrd;
> +	bool running;
> +	int ret;
> +
> +	if (!enable)
> +		return -EOPNOTSUPP;
> +
> +	/* Stop any background scrub currently in progress */
> +	if (ras2_ctx->bg_scrub) {
> +		ret = ras2_hw_scrub_set_enabled_bg(dev, drv_data, false);
> +		if (ret)
> +			return ret;
> +
> +		ras2_ctx->reenable_bg_scrub = true;
> +		thrd = kthread_run(ras2_scrub_monitor_thread, ras2_ctx,
> +				   "ras2_scrub_nid%d", ras2_ctx->sys_comp_nid);

Can a race condition happen here if the new monitor thread runs immediately?

The thread would acquire the pcc_lock, call ras2_get_demand_scrub_running(),
and see that od_scrub is still false. Will it then mistakenly conclude the
demand scrub has already finished, prematurely restart the background scrub,
and exit before the main thread can even set od_scrub to true and start the
hardware scrub below?

> +		if (IS_ERR(thrd)) {
> +			ras2_ctx->reenable_bg_scrub = false;
> +			ras2_hw_scrub_set_enabled_bg(dev, drv_data, true);
> +			return PTR_ERR(thrd);
> +		}
> +	}
> +
> +	guard(mutex)(ras2_ctx->pcc_lock);
> +	ret = ras2_get_demand_scrub_running(ras2_ctx, &running);
> +	if (ret)
> +		return ret;
> +
> +	if (running)
> +		return -EBUSY;
> +
> +	/* May add more validity checks for the address range in the future if necessary */
> +	if (!ras2_ctx->size || ras2_ctx->base < ras2_ctx->mem_base) {

Is an upper bound check also needed here? 

Without verifying if ras2_ctx->size causes an integer wrap-around or exceeds
the valid NUMA node boundary (mem_base + mem_size), could userspace instruct
the hardware to access arbitrary physical addresses outside the designated
domain?

> +		dev_err(dev, "%s: Invalid address range, base=0x%llx size=0x%llx\n",
> +			__func__, ras2_ctx->base, ras2_ctx->size);
> +		return -ERANGE;
> +	}

[ ... ]

> +static struct auxiliary_driver ras2_mem_driver = {
> +	.name = RAS2_MEM_DEV_ID_NAME,
> +	.probe = ras2_probe,
> +	.id_table = ras2_mem_dev_id_table,
> +};
> +module_auxiliary_driver(ras2_mem_driver);

Does this driver need a .remove callback to clean up its resources?

Since the probe function calls edac_dev_register() and potentially spawns
ras2_scrub_monitor_thread via kthread_run(), unloading the module without
unregistering the EDAC device will leave sysfs nodes pointing to unmapped
memory.

Additionally, since the task_struct pointer from kthread_run() is discarded,
is it possible to stop the thread on module unload? If not, will the thread
continue running and attempt to execute freed module memory, resulting in a
use-after-free kernel panic?

