    "content": "{"content":"\n/*\n * edac_device.c\n * (C) 2007 www.douglaskthompson.com\n *\n * This file may be distributed under the terms of the\n * GNU General Public License.\n *\n * Written by Doug Thompson <norsk5@xmission.com>\n *\n * edac_device API implementation\n * 19 Jan 2007\n */\n\n#include <asm/page.h>\n#include <linux/uaccess.h>\n#include <linux/ctype.h>\n#include <linux/highmem.h>\n#include <linux/init.h>\n#include <linux/jiffies.h>\n#include <linux/module.h>\n#include <linux/slab.h>\n#include <linux/smp.h>\n#include <linux/spinlock.h>\n#include <linux/sysctl.h>\n#include <linux/timer.h>\n\n#include \"edac_device.h\"\n#include \"edac_module.h\"\n\n/* lock for the list: 'edac_device_list', manipulation of this list\n * is protected by the 'device_ctls_mutex' lock\n */\nstatic DEFINE_MUTEX(device_ctls_mutex);\nstatic LIST_HEAD(edac_device_list);\n\n/* Default workqueue processing interval on this instance, in msecs */\n#define DEFAULT_POLL_INTERVAL 1000\n\n#ifdef CONFIG_EDAC_DEBUG\nstatic void edac_device_dump_device(struct edac_device_ctl_info *edac_dev)\n{\n\tedac_dbg(3, \"\\tedac_dev = %p dev_idx=%d\\n\",\n\t\t edac_dev, edac_dev->dev_idx);\n\tedac_dbg(4, \"\\tedac_dev->edac_check = %p\\n\", edac_dev->edac_check);\n\tedac_dbg(3, \"\\tdev = %p\\n\", edac_dev->dev);\n\tedac_dbg(3, \"\\tmod_name:ctl_name = %s:%s\\n\",\n\t\t edac_dev->mod_name, edac_dev->ctl_name);\n\tedac_dbg(3, \"\\tpvt_info = %p\\n\\n\", edac_dev->pvt_info);\n}\n#endif\t\t\t\t/* CONFIG_EDAC_DEBUG */\n\n/*\n * @off_val: zero, 1, or other based offset\n */\nstruct edac_device_ctl_info *\nedac_device_alloc_ctl_info(unsigned pvt_sz, char *dev_name, unsigned nr_instances,\n\t\t\t   char *blk_name, unsigned nr_blocks, unsigned off_val,\n\t\t\t   int device_index)\n{\n\tstruct edac_device_block *dev_blk, *blk_p, *blk;\n\tstruct edac_device_instance *dev_inst, *inst;\n\tstruct edac_device_ctl_info *dev_ctl;\n\tunsigned instance, block;\n\tvoid *pvt;\n\tint err;\n\n\tedac_dbg(4, \"instances=%d blocks=%d\\n\", nr_instances, nr_blocks);\n\n\tdev_ctl = kzalloc_obj(struct edac_device_ctl_info);\n\tif (!dev_ctl)\n\t\treturn NULL;\n\n\tdev_inst = kzalloc_objs(struct edac_device_instance, nr_instances);\n\tif (!dev_inst)\n\t\tgoto free;\n\n\tdev_ctl->instances = dev_inst;\n\n\tdev_blk = kzalloc_objs(struct edac_device_block,\n\t\t\t       nr_instances * nr_blocks);\n\tif (!dev_blk)\n\t\tgoto free;\n\n\tdev_ctl->blocks = dev_blk;\n\n\tif (pvt_sz) {\n\t\tpvt = kzalloc(pvt_sz, GFP_KERNEL);\n\t\tif (!pvt)\n\t\t\tgoto free;\n\n\t\tdev_ctl->pvt_info = pvt;\n\t}\n\n\tdev_ctl->dev_idx\t= device_index;\n\tdev_ctl->nr_instances\t= nr_instances;\n\n\t/* Default logging of CEs and UEs */\n\tdev_ctl->log_ce = 1;\n\tdev_ctl->log_ue = 1;\n\n\t/* Name of this edac device */\n\tsnprintf(dev_ctl->name, sizeof(dev_ctl->name),\"%s\", dev_name);\n\n\t/* Initialize every Instance */\n\tfor (instance = 0; instance < nr_instances; instance++) {\n\t\tinst = &dev_inst[instance];\n\t\tinst->ctl = dev_ctl;\n\t\tinst->nr_blocks = nr_blocks;\n\t\tblk_p = &dev_blk[instance * nr_blocks];\n\t\tinst->blocks = blk_p;\n\n\t\t/* name of this instance */\n\t\tsnprintf(inst->name, sizeof(inst->name), \"%s%u\", dev_name, instance);\n\n\t\t/* Initialize every block in each instance */\n\t\tfor (block = 0; block < nr_blocks; block++) {\n\t\t\tblk = &blk_p[block];\n\t\t\tblk->instance = inst;\n\t\t\tsnprintf(blk->name, sizeof(blk->name),\n\t\t\t\t \"%s%d\", blk_name, block + off_val);\n\n\t\t\tedac_dbg(4, \"instance=%d inst_p=%p block=#%d block_p=%p name='%s'\\n\",\n\t\t\t\t instance, inst, block, blk, blk->name);\n\t\t}\n\t}\n\n\t/* Mark this instance as merely ALLOCATED */\n\tdev_ctl->op_state = OP_ALLOC;\n\n\t/*\n\t * Initialize the 'root' kobj for the edac_device controller\n\t */\n\terr = edac_device_register_sysfs_main_kobj(dev_ctl);\n\tif (err)\n\t\tgoto free;\n\n\t/* at this point, the root kobj is valid, and in order to\n\t * 'free' the object, then the function:\n\t *\tedac_device_unregister_sysfs_main_kobj() must be called\n\t * which will perform kobj unregistration and the actual free\n\t * will occur during the kobject callback operation\n\t */\n\n\treturn dev_ctl;\n\nfree:\n\t__edac_device_free_ctl_info(dev_ctl);\n\n\treturn NULL;\n}\nEXPORT_SYMBOL_GPL(edac_device_alloc_ctl_info);\n\nvoid edac_device_free_ctl_info(struct edac_device_ctl_info *ctl_info)\n{\n\tedac_device_unregister_sysfs_main_kobj(ctl_info);\n}\nEXPORT_SYMBOL_GPL(edac_device_free_ctl_info);\n\n/*\n * find_edac_device_by_dev\n *\tscans the edac_device list for a specific 'struct device *'\n *\n *\tlock to be held prior to call:\tdevice_ctls_mutex\n *\n *\tReturn:\n *\t\tpointer to control structure managing 'dev'\n *\t\tNULL if not found on list\n */\nstatic struct edac_device_ctl_info *find_edac_device_by_dev(struct device *dev)\n{\n\tstruct edac_device_ctl_info *edac_dev;\n\tstruct list_head *item;\n\n\tedac_dbg(0, \"\\n\");\n\n\tlist_for_each(item, &edac_device_list) {\n\t\tedac_dev = list_entry(item, struct edac_device_ctl_info, link);\n\n\t\tif (edac_dev->dev == dev)\n\t\t\treturn edac_dev;\n\t}\n\n\treturn NULL;\n}\n\n/*\n * add_edac_dev_to_global_list\n *\tBefore calling this function, caller must\n *\tassign a unique value to edac_dev->dev_idx.\n *\n *\tlock to be held prior to call:\tdevice_ctls_mutex\n *\n *\tReturn:\n *\t\t0 on success\n *\t\t1 on failure.\n */\nstatic int add_edac_dev_to_global_list(struct edac_device_ctl_info *edac_dev)\n{\n\tstruct list_head *item, *insert_before;\n\tstruct edac_device_ctl_info *rover;\n\n\tinsert_before = &edac_device_list;\n\n\t/* Determine if already on the list */\n\trover = find_edac_device_by_dev(edac_dev->dev);\n\tif (unlikely(rover != NULL))\n\t\tgoto fail0;\n\n\t/* Insert in ascending order by 'dev_idx', so find position */\n\tlist_for_each(item, &edac_device_list) {\n\t\trover = list_entry(item, struct edac_device_ctl_info, link);\n\n\t\tif (rover->dev_idx >= edac_dev->dev_idx) {\n\t\t\tif (unlikely(rover->dev_idx == edac_dev->dev_idx))\n\t\t\t\tgoto fail1;\n\n\t\t\tinsert_before = item;\n\t\t\tbreak;\n\t\t}\n\t}\n\n\tlist_add_tail_rcu(&edac_dev->link, insert_before);\n\treturn 0;\n\nfail0:\n\tedac_printk(KERN_WARNING, EDAC_MC,\n\t\t\t\"%s (%s) %s %s already assigned %d\\n\",\n\t\t\tdev_name(rover->dev), edac_dev_name(rover),\n\t\t\trover->mod_name, rover->ctl_name, rover->dev_idx);\n\treturn 1;\n\nfail1:\n\tedac_printk(KERN_WARNING, EDAC_MC,\n\t\t\t\"bug in low-level driver: attempt to assign\\n\"\n\t\t\t\"    duplicate dev_idx %d in %s()\\n\", rover->dev_idx,\n\t\t\t__func__);\n\treturn 1;\n}\n\n/*\n * del_edac_device_from_global_list\n */\nstatic void del_edac_device_from_global_list(struct edac_device_ctl_info\n\t\t\t\t\t\t*edac_device)\n{\n\tlist_del_rcu(&edac_device->link);\n\n\t/* these are for safe removal of devices from global list while\n\t * NMI handlers may be traversing list\n\t */\n\tsynchronize_rcu();\n\tINIT_LIST_HEAD(&edac_device->link);\n}\n\n/*\n * edac_device_workq_function\n *\tperforms the operation scheduled by a workq request\n *\n *\tthis workq is embedded within an edac_device_ctl_info\n *\tstructure, that needs to be polled for possible error events.\n *\n *\tThis operation is to acquire the list mutex lock\n *\t(thus preventing insertation or deletion)\n *\tand then call the device's poll function IFF this device is\n *\trunning polled and there is a poll function defined.\n */\nstatic void edac_device_workq_function(struct work_struct *work_req)\n{\n\tstruct delayed_work *d_work = to_delayed_work(work_req);\n\tstruct edac_device_ctl_info *edac_dev = to_edac_device_ctl_work(d_work);\n\n\tmutex_lock(&device_ctls_mutex);\n\n\t/* If we are being removed, bail out immediately */\n\tif (edac_dev->op_state == OP_OFFLINE) {\n\t\tmutex_unlock(&device_ctls_mutex);\n\t\treturn;\n\t}\n\n\t/* Only poll controllers that are running polled and have a check */\n\tif ((edac_dev->op_state == OP_RUNNING_POLL) &&\n\t\t(edac_dev->edac_check != NULL)) {\n\t\t\tedac_dev->edac_check(edac_dev);\n\t}\n\n\tmutex_unlock(&device_ctls_mutex);\n\n\t/* Reschedule the workq for the next time period to start again\n\t * if the number of msec is for 1 sec, then adjust to the next\n\t * whole one second to save timers firing all over the period\n\t * between integral seconds\n\t */\n\tif (edac_dev->poll_msec == DEFAULT_POLL_INTERVAL)\n\t\tedac_queue_work(&edac_dev->work, round_jiffies_relative(edac_dev->delay));\n\telse\n\t\tedac_queue_work(&edac_dev->work, edac_dev->delay);\n}\n\n/*\n * edac_device_workq_setup\n *\tinitialize a workq item for this edac_device instance\n *\tpassing in the new delay period in msec\n */\nstatic void edac_device_workq_setup(struct edac_device_ctl_info *edac_dev,\n\t\t\t\t    unsigned msec)\n{\n\tedac_dbg(0, \"\\n\");\n\n\t/* take the arg 'msec' and set it into the control structure\n\t * to used in the time period calculation\n\t * then calc the number of jiffies that represents\n\t */\n\tedac_dev->poll_msec = msec;\n\tedac_dev->delay = msecs_to_jiffies(msec);\n\n\tINIT_DELAYED_WORK(&edac_dev->work, edac_device_workq_function);\n\n\t/* optimize here for the 1 second case, which will be normal value, to\n\t * fire ON the 1 second time event. This helps reduce all sorts of\n\t * timers firing on sub-second basis, while they are happy\n\t * to fire together on the 1 second exactly\n\t */\n\tif (edac_dev->poll_msec == DEFAULT_POLL_INTERVAL)\n\t\tedac_queue_work(&edac_dev->work, round_jiffies_relative(edac_dev->delay));\n\telse\n\t\tedac_queue_work(&edac_dev->work, edac_dev->delay);\n}\n\n/*\n * edac_device_workq_teardown\n *\tstop the workq processing on this edac_dev\n */\nstatic void edac_device_workq_teardown(struct edac_device_ctl_info *edac_dev)\n{\n\tif (!edac_dev->edac_check)\n\t\treturn;\n\n\tedac_dev->op_state = OP_OFFLINE;\n\n\tedac_stop_work(&edac_dev->work);\n}\n\n/*\n * edac_device_reset_delay_period\n *\n *\tneed to stop any outstanding workq queued up at this time\n *\tbecause we will be resetting the sleep time.\n *\tThen restart the workq on the new delay\n */\nvoid edac_device_reset_delay_period(struct edac_device_ctl_info *edac_dev,\n\t\t\t\t    unsigned long msec)\n{\n\tedac_dev->poll_msec = msec;\n\tedac_dev->delay\t    = msecs_to_jiffies(msec);\n\n\t/* See comment in edac_device_workq_setup() above */\n\tif (edac_dev->poll_msec == DEFAULT_POLL_INTERVAL)\n\t\tedac_mod_work(&edac_dev->work, round_jiffies_relative(edac_dev->delay));\n\telse\n\t\tedac_mod_work(&edac_dev->work, edac_dev->delay);\n}\n\nint edac_device_alloc_index(void)\n{\n\tstatic atomic_t device_indexes = ATOMIC_INIT(0);\n\n\treturn atomic_inc_return(&device_indexes) - 1;\n}\nEXPORT_SYMBOL_GPL(edac_device_alloc_index);\n\nint edac_device_add_device(struct edac_device_ctl_info *edac_dev)\n{\n\tedac_dbg(0, \"\\n\");\n\n#ifdef CONFIG_EDAC_DEBUG\n\tif (edac_debug_level >= 3)\n\t\tedac_device_dump_device(edac_dev);\n#endif\n\tmutex_lock(&device_ctls_mutex);\n\n\tif (add_edac_dev_to_global_list(edac_dev))\n\t\tgoto fail0;\n\n\t/* set load time so that error rate can be tracked */\n\tedac_dev->start_time = jiffies;\n\n\t/* create this instance's sysfs entries */\n\tif (edac_device_create_sysfs(edac_dev)) {\n\t\tedac_device_printk(edac_dev, KERN_WARNING,\n\t\t\t\t\t\"failed to create sysfs device\\n\");\n\t\tgoto fail1;\n\t}\n\n\t/* If there IS a check routine, then we are running POLLED */\n\tif (edac_dev->edac_check != NULL) {\n\t\t/* This instance is NOW RUNNING */\n\t\tedac_dev->op_state = OP_RUNNING_POLL;\n\n\t\tedac_device_workq_setup(edac_dev, edac_dev->poll_msec ?: DEFAULT_POLL_INTERVAL);\n\t} else {\n\t\tedac_dev->op_state = OP_RUNNING_INTERRUPT;\n\t}\n\n\t/* Report action taken */\n\tedac_device_printk(edac_dev, KERN_INFO,\n\t\t\"Giving out device to module %s controller %s: DEV %s (%s)\\n\",\n\t\tedac_dev->mod_name, edac_dev->ctl_name, edac_dev->dev_name,\n\t\tedac_op_state_to_string(edac_dev->op_state));\n\n\tmutex_unlock(&device_ctls_mutex);\n\treturn 0;\n\nfail1:\n\t/* Some error, so remove the entry from the lsit */\n\tdel_edac_device_from_global_list(edac_dev);\n\nfail0:\n\tmutex_unlock(&device_ctls_mutex);\n\treturn 1;\n}\nEXPORT_SYMBOL_GPL(edac_device_add_device);\n\nstruct edac_device_ctl_info *edac_device_del_device(struct device *dev)\n{\n\tstruct edac_device_ctl_info *edac_dev;\n\n\tedac_dbg(0, \"\\n\");\n\n\tmutex_lock(&device_ctls_mutex);\n\n\t/* Find the structure on the list, if not there, then leave */\n\tedac_dev = find_edac_device_by_dev(dev);\n\tif (edac_dev == NULL) {\n\t\tmutex_unlock(&device_ctls_mutex);\n\t\treturn NULL;\n\t}\n\n\t/* mark this instance as OFFLINE */\n\tedac_dev->op_state = OP_OFFLINE;\n\n\t/* deregister from global list */\n\tdel_edac_device_from_global_list(edac_dev);\n\n\tmutex_unlock(&device_ctls_mutex);\n\n\t/* clear workq processing on this instance */\n\tedac_device_workq_teardown(edac_dev);\n\n\t/* Tear down the sysfs entries for this instance */\n\tedac_device_remove_sysfs(edac_dev);\n\n\tedac_printk(KERN_INFO, EDAC_MC,\n\t\t\"Removed device %d for %s %s: DEV %s\\n\",\n\t\tedac_dev->dev_idx,\n\t\tedac_dev->mod_name, edac_dev->ctl_name, edac_dev_name(edac_dev));\n\n\treturn edac_dev;\n}\nEXPORT_SYMBOL_GPL(edac_device_del_device);\n\nstatic inline int edac_device_get_log_ce(struct edac_device_ctl_info *edac_dev)\n{\n\treturn edac_dev->log_ce;\n}\n\nstatic inline int edac_device_get_log_ue(struct edac_device_ctl_info *edac_dev)\n{\n\treturn edac_dev->log_ue;\n}\n\nstatic inline int edac_device_get_panic_on_ue(struct edac_device_ctl_info\n\t\t\t\t\t*edac_dev)\n{\n\treturn edac_dev->panic_on_ue;\n}\n\nvoid edac_device_handle_ce_count(struct edac_device_ctl_info *edac_dev,\n\t\t\t\t unsigned int count, int inst_nr, int block_nr,\n\t\t\t\t const char *msg)\n{\n\tstruct edac_device_instance *instance;\n\tstruct edac_device_block *block = NULL;\n\n\tif (!count)\n\t\treturn;\n\n\tif ((inst_nr >= edac_dev->nr_instances) || (inst_nr < 0)) {\n\t\tedac_device_printk(edac_dev, KERN_ERR,\n\t\t\t\t\"INTERNAL ERROR: 'instance' out of range \"\n\t\t\t\t\"(%d >= %d)\\n\", inst_nr,\n\t\t\t\tedac_dev->nr_instances);\n\t\treturn;\n\t}\n\n\tinstance = edac_dev->instances + inst_nr;\n\n\tif ((block_nr >= instance->nr_blocks) || (block_nr < 0)) {\n\t\tedac_device_printk(edac_dev, KERN_ERR,\n\t\t\t\t\"INTERNAL ERROR: instance %d 'block' \"\n\t\t\t\t\"out of range (%d >= %d)\\n\",\n\t\t\t\tinst_nr, block_nr,\n\t\t\t\tinstance->nr_blocks);\n\t\treturn;\n\t}\n\n\tif (instance->nr_blocks > 0) {\n\t\tblock = instance->blocks + block_nr;\n\t\tblock->counters.ce_count += count;\n\t}\n\n\t/* Propagate the count up the 'totals' tree */\n\tinstance->counters.ce_count += count;\n\tedac_dev->counters.ce_count += count;\n\n\tif (edac_device_get_log_ce(edac_dev))\n\t\tedac_device_printk(edac_dev, KERN_WARNING,\n\t\t\t\t   \"CE: %s instance: %s block: %s count: %d '%s'\\n\",\n\t\t\t\t   edac_dev->ctl_name, instance->name,\n\t\t\t\t   block ? block->name : \"N/A\", count, msg);\n}\nEXPORT_SYMBOL_GPL(edac_device_handle_ce_count);\n\nvoid edac_device_handle_ue_count(struct edac_device_ctl_info *edac_dev,\n\t\t\t\t unsigned int count, int inst_nr, int block_nr,\n\t\t\t\t const char *msg)\n{\n\tstruct edac_device_instance *instance;\n\tstruct edac_device_block *block = NULL;\n\n\tif (!count)\n\t\treturn;\n\n\tif ((inst_nr >= edac_dev->nr_instances) || (inst_nr < 0)) {\n\t\tedac_device_printk(edac_dev, KERN_ERR,\n\t\t\t\t\"INTERNAL ERROR: 'instance' out of range \"\n\t\t\t\t\"(%d >= %d)\\n\", inst_nr,\n\t\t\t\tedac_dev->nr_instances);\n\t\treturn;\n\t}\n\n\tinstance = edac_dev->instances + inst_nr;\n\n\tif ((block_nr >= instance->nr_blocks) || (block_nr < 0)) {\n\t\tedac_device_printk(edac_dev, KERN_ERR,\n\t\t\t\t\"INTERNAL ERROR: instance %d 'block' \"\n\t\t\t\t\"out of range (%d >= %d)\\n\",\n\t\t\t\tinst_nr, block_nr,\n\t\t\t\tinstance->nr_blocks);\n\t\treturn;\n\t}\n\n\tif (instance->nr_blocks > 0) {\n\t\tblock = instance->blocks + block_nr;\n\t\tblock->counters.ue_count += count;\n\t}\n\n\t/* Propagate the count up the 'totals' tree */\n\tinstance->counters.ue_count += count;\n\tedac_dev->counters.ue_count += count;\n\n\tif (edac_device_get_log_ue(edac_dev))\n\t\tedac_device_printk(edac_dev, KERN_EMERG,\n\t\t\t\t   \"UE: %s instance: %s block: %s count: %d '%s'\\n\",\n\t\t\t\t   edac_dev->ctl_name, instance->name,\n\t\t\t\t   block ? block->name : \"N/A\", count, msg);\n\n\tif (edac_device_get_panic_on_ue(edac_dev))\n\t\tpanic(\"EDAC %s: UE instance: %s block %s count: %d '%s'\\n\",\n\t\t      edac_dev->ctl_name, instance->name,\n\t\t      block ? block->name : \"N/A\", count, msg);\n}\nEXPORT_SYMBOL_GPL(edac_device_handle_ue_count);\n\nstatic void edac_dev_release(struct device *dev)\n{\n\tstruct edac_dev_feat_ctx *ctx = container_of(dev, struct edac_dev_feat_ctx, dev);\n\n\tkfree(ctx->mem_repair);\n\tkfree(ctx->scrub);\n\tkfree(ctx->dev.groups);\n\tkfree(ctx);\n}\n\nstatic const struct device_type edac_dev_type = {\n\t.name = \"edac_dev\",\n\t.release = edac_dev_release,\n};\n\nstatic void edac_dev_unreg(void *data)\n{\n\tdevice_unregister(data);\n}\n\n/**\n * edac_dev_register - register device for RAS features with EDAC\n * @parent: parent device.\n * @name: name for the folder in the /sys/bus/edac/devices/,\n *\t  which is derived from the parent device.\n *\t  For e.g. /sys/bus/edac/devices/cxl_mem0/\n * @private: parent driver's data to store in the context if any.\n * @num_features: number of RAS features to register.\n * @ras_features: list of RAS features to register.\n *\n * Return:\n *  * %0       - Success.\n *  * %-EINVAL - Invalid parameters passed.\n *  * %-ENOMEM - Dynamic memory allocation failed.\n *\n */\nint edac_dev_register(struct device *parent, char *name,\n\t\t      void *private, int num_features,\n\t\t      const struct edac_dev_feature *ras_features)\n{\n\tconst struct attribute_group **ras_attr_groups;\n\tstruct edac_dev_data *dev_data;\n\tstruct edac_dev_feat_ctx *ctx;\n\tint mem_repair_cnt = 0;\n\tint attr_gcnt = 0;\n\tint ret = -ENOMEM;\n\tint